import numpy as np

def predict(frame, action):
    out = frame.copy()
    H, W = out.shape

    TOP = np.array([2, 1, 1, 2, 1, 1])
    BOT = np.array([1, 1, 2, 1, 1, 2])

    def is_all4(r, c):
        return (out[r:r+2, c:c+6] == 4).all()

    def is_pattern(r, c):
        return np.array_equal(out[r, c:c+6], TOP) and np.array_equal(out[r+1, c:c+6], BOT)

    def stamp_pattern(r, c):
        out[r, c:c+6] = TOP
        out[r+1, c:c+6] = BOT

    def stamp_4(r, c):
        out[r:r+2, c:c+6] = 4

    if action == 6:
        return out

    if action == 4:
        # Convert an existing all-4 block to the 2/1 fill (toggle on);
        # prefer the rightmost such block (the active head).
        best = None
        for r in range(H - 1):
            for c in range(W - 5):
                if is_all4(r, c):
                    # require it to be a bounded 2x6 head (left/right not extending 4s)
                    left_ok = c == 0 or (out[r, c-1] != 4 and out[r+1, c-1] != 4)
                    right_ok = c + 6 >= W or (out[r, c+6] != 4 and out[r+1, c+6] != 4)
                    if left_ok and right_ok:
                        if best is None or c > best[1]:
                            best = (r, c)
        if best is not None:
            stamp_pattern(*best)
            return out
        # Otherwise advance: place a new fill 6 cols right of the rightmost fill.
        best = None
        for r in range(H - 1):
            for c in range(W - 5):
                if is_pattern(r, c):
                    if best is None or c > best[1]:
                        best = (r, c)
        if best is not None and best[1] + 12 <= W:
            stamp_pattern(best[0], best[1] + 6)
        return out

    if action == 3:
        # Convert a 2/1 fill block back to all-4 (toggle off); rightmost head.
        best = None
        for r in range(H - 1):
            for c in range(W - 5):
                if is_pattern(r, c):
                    if best is None or c > best[1]:
                        best = (r, c)
        if best is not None:
            stamp_4(*best)
        # Advance the counter at row 53 leftward (drop a 3 left of the leftmost 3).
        threes = np.where(out[53] == 3)[0]
        if threes.size:
            nc = threes.min() - 1
        else:
            nc = W - 1
        if 0 <= nc < W:
            out[53, nc] = 3
        return out

    # actions 1, 2 and any others: complex history-dependent stamp — leave unchanged.
    return out
